		const Y0 = j - t;
		const x0 = xin - X0;
		const y0 = yin - Y0;
		let i1;
		let j1;
		if (x0 > y0) {
			i1 = 1;
			j1 = 0;
		} else {
			i1 = 0;
			j1 = 1;
		}
